/**
 * marked - Minimal vendored markdown parser for the registry SPA.
 *
 * Handles: headings, bold, italic, code blocks, inline code, links,
 * unordered lists, ordered lists, blockquotes, horizontal rules,
 * and line breaks.
 *
 * Replace with the full marked.js library for production use:
 *   https://cdn.jsdelivr.net/npm/marked/marked.min.js
 */
(function (global) {
    'use strict';

    function escapeHtml(text) {
        return text
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;');
    }

    function parse(src) {
        if (!src) return '';
        var html = escapeHtml(src);

        // Fenced code blocks: ```lang\n...\n```
        html = html.replace(/```(\w*)\n([\s\S]*?)```/g, function (_m, _lang, code) {
            return '<pre><code>' + code + '</code></pre>';
        });

        // Inline code
        html = html.replace(/`([^`]+)`/g, '<code>$1</code>');

        // Headings (### h3, ## h2, # h1)
        html = html.replace(/^### (.+)$/gm, '<h3>$1</h3>');
        html = html.replace(/^## (.+)$/gm, '<h2>$1</h2>');
        html = html.replace(/^# (.+)$/gm, '<h1>$1</h1>');

        // Blockquotes
        html = html.replace(/^&gt; (.+)$/gm, '<blockquote>$1</blockquote>');

        // Horizontal rules
        html = html.replace(/^---$/gm, '<hr>');

        // Bold + italic
        html = html.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
        // Bold
        html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
        // Italic
        html = html.replace(/\*(.+?)\*/g, '<em>$1</em>');

        // Links: [text](url)
        html = html.replace(/\[([^\]]+)\]\(([^)]+)\)/g,
            '<a href="$2" target="_blank" rel="noopener">$1</a>');

        // Unordered lists (lines starting with "- ")
        html = html.replace(/^- (.+)$/gm, '<li>$1</li>');
        html = html.replace(/(<li>[\s\S]*?<\/li>)/g, '<ul>$1</ul>');
        // Collapse adjacent <ul> tags
        html = html.replace(/<\/ul>\s*<ul>/g, '');

        // Line breaks (preserve newlines as <br> outside of block elements)
        html = html.replace(/\n/g, '<br>');

        return html;
    }

    var marked = {
        parse: parse,
    };

    if (typeof module !== 'undefined' && module.exports) {
        module.exports = marked;
    } else {
        global.marked = marked;
    }
})(typeof globalThis !== 'undefined' ? globalThis : typeof window !== 'undefined' ? window : this);
